theme.css:
.quote {
    font-family: Roboto Medium;
    font-size: 32px;
    font-weight: 400;
    color: #191919;
    text-align: left;
}
.quotetitle {
    font-family: Roboto;
    font-size: 16px;
    font-weight: 400;
    color: #464646;
    text-align: left;
    line-height: 24px;
}
.quote .innertext {
    line-height: 38px;
}
.quote .quotetitle .innertext {
    line-height: 24px;
}
/* igc-pie:start */
svg .igc-semi-pie-center-text .igc-pie-center-text-node,
svg .igc-pie-center-text .igc-pie-center-text-node {
    font-family: Roboto Medium;
    font-size: 32px;
    font-weight: 400;
    fill: #464646;
}
/* igc-pie:end */

/*igc-textual:start*/
.igc-textual-figure {
    font-family: Roboto Medium;
    font-size: 32px;
    font-weight: 400;
}
.igc-textual-text.innertext {
    line-height: 38px;
}
.igc-textual-fact {
    color: #464646;
    font-family: Roboto;
    font-size: 16px;
    font-weight: 400;
}
.innertext .igc-textual-fact {
    line-height: 24px;
}
.igc-textual-icon {
    padding-right: 30px;
    padding-top: 7px;
}
/*igc-textual:end*/

.igc-table .igc-table-header {
    padding-left: 9px;
}
.ig-container {
    background: #FFFFFF;
}
.ig-copyright {
    display: none;
}
.headline {
    font-family: IBM Plex Sans;
    font-size: 36px;
    font-weight: 700;
    color: #191919;
    text-align: left;
    line-height: 1.2;
}
.chart-title {
    font-family: IBM Plex Sans;
    font-size: 24px;
    font-weight: 400;
    color: #191919;
    text-align: left;
}
.chart-title .innertext {
    line-height: 38px;
}
.bodytext {
    font-family: Roboto;
    font-size: 16px;
    font-weight: 400;
    color: #464646;
    text-align: left;
    line-height: 1.5;
}

.heatmap-legend {
	background: rgba(255,255,255,0.7);
}
.heatmap-legend-item,
.heatmap-label {
 	color: #464646;
	font-size: 14px;
	font-weight: 400;
	font-family: Roboto;
}
.igc-graph-pie-piece {
	stroke: rgb(255,255,255);
}


.captiontext {
    font-family: Roboto;
    color: #464646;
    font-size: 14px;
    font-weight: 400;
    text-align: left;
    line-height: 1.5
}


.igc-table-search {
    color: #232323;
    font-size: 14px;
    font-weight: 400;
    font-family: Roboto Medium;
}

svg .igc-pie-center-text .igc-pie-center-text-node {
	font-family: Roboto Medium, sans-serif;
	font-weight: 400;
	fill: #464646;
	font-size: 19px;
}
.igc-sheet {
	margin-bottom: 15px;
}
.igc-sheets {
	margin-bottom: 15px;
}
.igc-sheets .igc-sheet .igc-sheet-label,
    .igc-sheets .igc-sheet:hover .igc-sheet-label,
        .igc-sheets .igc-sheet.active .igc-sheet-label {
	color: rgba(70, 70, 70, 1);
	margin-left: 5px;
	font: 400 13px Roboto Medium, sans-serif;
}
.igc-sheets .igc-sheet:hover .igc-sheet-label,.igc-sheets .igc-sheet.active .igc-sheet-label {
	color: rgba(70, 70, 70, 0.7);
}
.igc-sheets .igc-sheet .igc-sheet-ico,
    .igc-sheets .igc-sheet:hover .igc-sheet-ico {
	background: rgba(167, 167, 167, 0.3);
	border-color: #464646;
	transition: .2s;
}
.igc-sheets .igc-sheet:hover .igc-sheet-ico {
	background: rgba(167, 167, 167, 1);
}
.igc-sheets .igc-sheet.active .igc-sheet-ico {
	background: #464646;
}
.igc-sheets .igc-sheet.active .igc-sheet-ico::after,
    .igc-sheets .igc-sheet:hover .igc-sheet-ico::after {
	height: 6px;
	width: 6px;
	left: 6px;
	top: 6px;
	background: #fff;
}
.igc-textual-figure {
	font: 400 29px Roboto Medium, sans-serif;
}
.igc-textual-fact {
	color: #464646;
	line-height: 18px;
	font: 400 15px Roboto Medium, sans-serif;
}
.igc-textual-figure .innertext {
	line-height: 30px;
}
.igc-textual-fact .innertext {
	line-height: 19px;
}
.igc-textual-icon {
	padding-right: 30px;
	padding-top: 7px;
}
.igc-table .igc-table-cell {
	font: 400 13px Roboto Medium, sans-serif;
}
.igc-table .igc-table-header {
	font: 400 13px Roboto Medium, sans-serif;
	padding-left: 9px;
}
.ig-container {
	background: #fff;
}
.headline {
	font-weight: 400;
	font-size: 39px;
	font-family: Roboto;
